ALGORITHM BPTT(X, Y, θ)
// X = input sequence [x₁, x₂, ..., x_T]
// Y = target sequence [y₁, y₂, ..., y_T]
// θ = {Whh, Wxh, Wy, bh, by}

BEGIN
  SET h₀ ← zeros(initial_hidden_size)
  SET h_history ← [h₀]

  // Step 1: Forward Pass
  FOR t FROM 1 TO T DO
    z_t ← Whh × h_{t-1} + Wxh × x_t + b_h
    h_t ← tanh(z_t)           // Store h_t for backward pass
    y_pred_t ← Wy × h_t + b_y
    APPEND h_t TO h_history
  END FOR

  // Step 2: Compute Loss
  L ← Σ_{t=1}^{T} Loss(y_pred_t, y_t)

  // Step 3: Initialize Gradients
  SET dWhh, dWxh, dWy, dbh, dby ← 0
  SET dh_next ← 0

  // Step 4: Backward Pass (through time)
  FOR t FROM T DOWN TO 1 DO
    // Gradient from output
    dy_t ← ∂L/∂y_pred_t
    dWy ← dWy + dy_t × h_t^T
    dby ← dby + dy_t

    // Gradient to hidden state
    dh_t ← Wy^T × dy_t + dh_next

    // Gradient through tanh activation
    dz_t ← dh_t ∘ (1 - tanh²(z_t))    // ∘ = element-wise

    // Accumulate weight gradients
    dWxh ← dWxh + dz_t × x_t^T
    dWhh ← dWhh + dz_t × h_{t-1}^T
    dbh ← dbh + dz_t

    // Propagate gradient to previous time step
    dh_next ← Whh^T × dz_t
  END FOR

  // Step 5: Update Parameters
  θ ← θ - η × gradients

  RETURN θ, L
END
